import React, { useState, useEffect, useMemo, useCallback } from "react";
import { useQueryClient } from "@tanstack/react-query";
import { getApiErrorMessage } from "@/api/app/apiError";
import { format, parseISO } from "date-fns";
import {
  Download, Loader2,
  AlertCircle,
  Clock, SunMedium, EyeOff,
  Calendar, UserCheck,
} from "lucide-react";
import { extraShiftService } from "@/api/extraShiftService";
import type { ExtraShiftDTO, CreateExtraShiftDTO } from "@/types/dto";
import { useAuth } from "@/shared/AuthContext";
import { toast } from "sonner";
import { PERMISSIONS } from "@/constants/permissions";
import { Button } from "@/shadcn/components/ui/button";
import { HarmonyDialog } from "@/components/ui/harmony-dialog";
import HarmonyForm, { type FormSchema } from "@/components/forms/HarmonyForm";
import { useLeavesListQuery } from "@/features/leave-management/hooks/leaveHooks";
import { useSearchParams } from "react-router-dom";
import { HarmonyFullCalendar } from "@/components/ui/harmony-full-calendar";

// Feature specific
import type { WorkScheduleResponse, ExportData } from "@/features/work-schedule/types";
import {
  getMemberNameFromSchedule,
  type PublicHoliday
} from "@/features/work-schedule/utils";
import { ShiftType, LeaveType, LeaveSize } from "@/types/enums";
import { useWorkScheduleData } from "@/features/work-schedule/hooks/useWorkScheduleData";
import { useWorkScheduleMutations } from "@/features/work-schedule/hooks/useWorkScheduleMutations";

/* ============================
   COMPONENT
   ============================ */

const TeamSchedule: React.FC = () => {
  const { hasPermission, user } = useAuth();

  const isAdmin = hasPermission(PERMISSIONS.WorkSchedule.Approve) || hasPermission(PERMISSIONS.WorkSchedule.Reject);

  /* ── STATE ── */
  const [searchParams] = useSearchParams();
  const [currentDate, setCurrentDate] = useState(() => {
    const y = searchParams.get('year');
    const m = searchParams.get('month');
    if (y && m) return new Date(parseInt(y), parseInt(m) - 1, 1);
    return new Date();
  });

  const [showHolidays, setShowHolidays] = useState(true);

  // Context Menu & Leave Modal
  const [contextMenu, setContextMenu] = useState<{ x: number, y: number, date: string } | null>(null);
  const [isLeaveModalOpen, setIsLeaveModalOpen] = useState(false);
  const [selectedLeaveDate, setSelectedLeaveDate] = useState<string | null>(null);

  // Extra Shift Modal
  const [isExtraShiftModalOpen, setIsExtraShiftModalOpen] = useState(false);
  const [selectedExtraShiftDate, setSelectedExtraShiftDate] = useState<string | null>(null);
  const [extraShiftReason, setExtraShiftReason] = useState("");
  const [extraShiftType, setExtraShiftType] = useState<ShiftType>(ShiftType.MorningShift);

  const year = currentDate.getFullYear();
  const monthNumber = currentDate.getMonth() + 1;

  /* ── DATA & MUTATIONS ── */
  const { scheduleQuery, extraShiftQuery, holidayQuery } = useWorkScheduleData(year, monthNumber, isAdmin);
  const { data, isLoading, isError, error } = scheduleQuery;
  const { data: extraShifts = [] } = extraShiftQuery;
  const { data: allHolidays = [] } = holidayQuery;

  const { data: leavesData } = useLeavesListQuery({
    year,
    month: monthNumber,
    pageSize: 100
  });

  const mutations = useWorkScheduleMutations(year, monthNumber, isAdmin);
  const { leaveMutation } = mutations;

  const queryClient = useQueryClient();

  const holidays = useMemo<PublicHoliday[]>(
    () =>
      allHolidays.filter((h) => {
        try { return parseISO(h.date).getFullYear() === year; }
        catch { return false; }
      }),
    [allHolidays, year],
  );

  /* ── DATA EXTRACTION ── */
  const teamSchedules = useMemo<WorkScheduleResponse[]>(() => {
    if (!data) return [];
    return Array.isArray(data) ? (data as unknown as WorkScheduleResponse[]) : [data];
  }, [data]);

  /* ── HANDLERS ── */

  const handleExport = useCallback(() => {
    const rows: ExportData[] = [];
    for (const schedule of teamSchedules) {
      const memberName = getMemberNameFromSchedule(schedule);
      schedule.days
        .filter((d) => d.shiftType && !d.shiftType.toLowerCase().includes("holiday"))
        .forEach((d) =>
          rows.push({ member: memberName, date: d.date, shift: d.shiftType!, task: d.workDescription || "N/A" }),
        );
    }
    const csv = [
      ["Member", "Date", "Shift", "Task"].join(","),
      ...rows.map((r) => [r.member, r.date, `"${r.shift}"`, `"${r.task}"`].join(",")),
    ].join("\n");
    const a = Object.assign(document.createElement("a"), {
      href: URL.createObjectURL(new Blob([csv], { type: "text/csv" })),
      download: `schedule-${format(currentDate, "yyyy-MM")}.csv`,
    });
    a.click();
    URL.revokeObjectURL(a.href);
  }, [teamSchedules, currentDate]);

  const handleLeaveSubmit = (formData: Record<string, unknown>) => {
    if (!user?.id || !selectedLeaveDate) return;

    const payload = {
      userProfileId: user.id,
      leaveDate: selectedLeaveDate,
      leaveType: formData.leaveType as LeaveType | undefined,
      leaveSize: formData.leaveSize as LeaveSize | undefined,
      reason: formData.reason as string,
    };

    leaveMutation.mutate(payload, {
      onSuccess: () => {
        setIsLeaveModalOpen(false);
        setSelectedLeaveDate(null);
        toast.success("Leave request submitted.");
      }
    });
  };

  const leaveFormSchema: FormSchema = {
    formKey: "leave-request-context-form",
    title: "Time Off Request",
    fields: [
      {
        name: "leaveType",
        label: "Leave Type",
        inputType: "select",
        required: true,
        options: [
          { label: "Planned", value: "0" },
          { label: "Unplanned", value: "1" },
        ],
      },
      {
        name: "leaveSize",
        label: "Leave Size",
        inputType: "select",
        required: true,
        options: [
          { label: "Full Day", value: "0" },
          { label: "First Half", value: "1" },
          { label: "Second Half", value: "2" },
        ],
      },
      {
        name: "reason",
        label: "Reason",
        inputType: "textarea",
        required: true,
      },
    ]
  };

  const handleExtraShiftSubmit = async () => {
    if (!selectedExtraShiftDate || !extraShiftReason.trim() || !user?.id) return;

    try {
      const payload: CreateExtraShiftDTO = {
        userProfileId: user.id,
        date: selectedExtraShiftDate,
        shiftType: extraShiftType,
        reason: extraShiftReason,
      };

      await extraShiftService.create(payload);

      // Refresh extra shifts and schedule
      queryClient.invalidateQueries({ queryKey: ["extra-shifts", year, monthNumber] });
      queryClient.invalidateQueries({ queryKey: ["work-schedule", year, monthNumber] });

      setIsExtraShiftModalOpen(false);
      setSelectedExtraShiftDate(null);
      setExtraShiftReason("");
      setExtraShiftType(ShiftType.MorningShift);
      toast.success("Extra shift added to schedule.");
    } catch (err) {
      toast.error(getApiErrorMessage(err));
    }
  };

  useEffect(() => {
    const handleClick = () => setContextMenu(null);
    window.addEventListener("click", handleClick);
    return () => window.removeEventListener("click", handleClick);
  }, []);

  /* ── LOADING / ERROR ── */
  if (isLoading) return (
    <div className="flex items-center justify-center min-h-125">
      <div className="flex flex-col items-center gap-4 text-muted-foreground">
        <div className="relative">
          <div className="w-12 h-12 rounded-2xl bg-primary/10 flex items-center justify-center">
            <Loader2 className="w-6 h-6 animate-spin text-primary" />
          </div>
        </div>
        <div className="text-center">
          <p className="text-sm font-semibold text-foreground">Loading schedule</p>
          <p className="text-xs text-muted-foreground mt-0.5">Fetching your work data…</p>
        </div>
      </div>
    </div>
  );

  if (isError) {
    const msg = getApiErrorMessage(error);
    const is400 = msg.includes("400") || String(error).includes("400");
    return (
      <div className="p-10 my-10 bg-rose-50 border border-rose-200/80 rounded-3xl text-center flex flex-col items-center gap-5 max-w-2xl mx-auto shadow-sm">
        <div className="w-14 h-14 bg-rose-100 rounded-2xl flex items-center justify-center">
          <AlertCircle className="w-7 h-7 text-rose-500" />
        </div>
        <div>
          <h3 className="text-xl font-bold text-rose-900">
            {is400 ? "Schedule Not Available" : "Something went wrong"}
          </h3>
          <p className="text-rose-600 text-sm mt-1.5 font-medium">
            {is400 ? `No schedule data exists for ${format(currentDate, "MMMM yyyy")}.` : msg}
          </p>
        </div>
        <div className="flex gap-3 mt-1">
          <button onClick={() => setCurrentDate((d) => { const prev = new Date(d); prev.setMonth(prev.getMonth() - 1); return prev; })} className="px-5 py-2.5 bg-destructive/10 border border-destructive/20 text-destructive rounded-xl text-sm font-semibold hover:bg-destructive/20 transition-colors shadow-sm">
            ← Go Back
          </button>
          <button onClick={() => setCurrentDate(new Date())} className="px-6 py-2.5 bg-rose-600 text-white rounded-xl text-sm font-semibold hover:bg-rose-700 transition-colors shadow-sm shadow-rose-200">
            Current Month
          </button>
        </div>
      </div>
    );
  }

  /* ══════════════════════════════════════════════
     MAIN RENDER
     ══════════════════════════════════════════════ */
  return (
    <div className="page-wrapper flex flex-col" style={{ gap: 'var(--section-padding)' }}>

      {/* ────────────────────────────────────────
          HEADER PANEL
      ──────────────────────────────────────── */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 bg-card/80 p-8 rounded-[var(--radius-xl)] border border-border shadow-xl shadow-border/50">
        <div className="flex items-center gap-3">
          <div className="size-12 flex items-center justify-center rounded-(--radius-lg) bg-primary/10 shrink-0">
            <Calendar className="w-7 h-7 text-primary" />
          </div>
          <div className="space-y-1">
            <div className="flex items-center gap-3 flex-wrap">
              <h1 className="page-title">Team Schedule</h1>
            </div>
            <p className="page-subtitle">View, manage, and submit your monthly work schedule.</p>
          </div>
        </div>
      </div>

      {/* ── ACTION & FILTER STRIP ── */}
      <div className="bg-card/80 rounded-[var(--radius-xl)] border border-border shadow-xl shadow-border/30 overflow-hidden mb-6">
        {/* Filters strip */}
        <div className="px-6 py-4 space-y-4">
          <div className="flex flex-wrap items-center gap-x-4 gap-y-2">
            <button
              onClick={() => setShowHolidays((v) => !v)}
              className={`inline-flex items-center gap-2 px-3.5 py-2 rounded-xl border text-xs font-semibold transition-all ${showHolidays
                ? "bg-amber-50 dark:bg-amber-950/30 border-amber-200 dark:border-amber-800 text-amber-700 dark:text-amber-400 shadow-sm"
                : "bg-card border-border text-muted-foreground hover:border-border hover:bg-muted"
                }`}
            >
              {showHolidays ? <SunMedium className="w-3.5 h-3.5" /> : <EyeOff className="w-3.5 h-3.5" />}
              {showHolidays ? `Holidays Visible (${holidays.length})` : "Holidays Hidden"}
            </button>

            <div className="ml-auto flex items-center gap-3">
              {isAdmin && (
                <div className="inline-flex items-center gap-2 px-3 py-1.5 bg-primary/10 border border-primary/20 rounded-xl">
                  <UserCheck className="w-3.5 h-3.5 text-primary" />
                  <span className="text-[11px] font-bold text-primary uppercase tracking-wider">Admin Mode</span>
                </div>
              )}
              <Button
                variant="secondary"
                size="sm"
                onClick={handleExport}
                className="font-semibold"
              >
                <Download size={15} />
                Export CSV
              </Button>
            </div>
          </div>
        </div>
      </div>

      {/* CALENDAR PANEL */}
      <HarmonyFullCalendar
        schedules={teamSchedules}
        publicHolidays={showHolidays ? holidays : []}
        leaves={leavesData?.data}
        extraShifts={extraShifts as ExtraShiftDTO[]}
        initialDate={currentDate}
        editable={false}
        showMemberFilter={true}
        isLoading={isLoading}
        onDateContextMenu={(date, x, y) => {
          setContextMenu({ x, y, date });
        }}
      />

      {/* ══════════════════════════════════════════
          MODALS
         ══════════════════════════════════════════ */}

      {/* Shared modal styles */}
      <style>{`
        .ws-label {
          display: block;
          font-size: 10px;
          font-weight: 700;
          color: var(--color-muted-foreground);
          text-transform: uppercase;
          letter-spacing: 0.08em;
          margin-bottom: 6px;
        }
      `}</style>

      {/* ── CONTEXT MENU ── */}
      {contextMenu && (
        <div
          role="menu"
          aria-label="Schedule context menu"
          className="fixed bg-card border border-border rounded-2xl shadow-xl shadow-black/10 z-100 py-2 min-w-40 overflow-hidden"
          style={{
            top: contextMenu.y,
            left: contextMenu.x,
          }}
        >
          <button
            role="menuitem"
            type="button"
            onClick={() => {
              setSelectedLeaveDate(contextMenu.date);
              setIsLeaveModalOpen(true);
              setContextMenu(null);
            }}
            className="w-full flex items-center gap-3 px-4 py-2.5 text-sm font-semibold text-foreground hover:bg-primary/10 hover:text-primary transition-colors text-left"
          >
            <div className="w-6 h-6 bg-primary/10 rounded-lg flex items-center justify-center shrink-0">
              <Calendar className="w-3.5 h-3.5 text-primary" />
            </div>
            Add Leave
          </button>
          <button
            role="menuitem"
            type="button"
            onClick={() => {
              setSelectedExtraShiftDate(contextMenu.date);
              setIsExtraShiftModalOpen(true);
              setContextMenu(null);
            }}
            className="w-full flex items-center gap-3 px-4 py-2.5 text-sm font-semibold text-foreground hover:bg-muted transition-colors text-left border-t border-border"
          >
            <div className="w-6 h-6 bg-muted rounded-lg flex items-center justify-center shrink-0">
              <Clock className="w-3.5 h-3.5 text-muted-foreground" />
            </div>
            Add extra Shift
          </button>
        </div>
      )}

      {/* ── LEAVE MODAL ── */}
      <HarmonyDialog
        open={isLeaveModalOpen}
        onOpenChange={(open) => { if (!open) { setIsLeaveModalOpen(false); setSelectedLeaveDate(null); } }}
        title="Time Off Request"
        description={selectedLeaveDate ? format(parseISO(selectedLeaveDate), "EEEE, dd MMMM yyyy") : ""}
        size="2xl"
        onSubmit={() => (document.querySelector('form') as HTMLFormElement)?.requestSubmit()}
        submitLabel="Submit Request"
        isSubmitting={leaveMutation.isPending}
      >
        <div>
          <HarmonyForm
            schema={leaveFormSchema}
            onSubmit={handleLeaveSubmit}
            hideSubmitButton={true}
            defaultValues={{
              leaveType: "0",
              leaveSize: "0",
              reason: ""
            }}
            isPending={leaveMutation.isPending}
          />
          {leaveMutation.isError && (
            <div className="mt-4 p-3.5 bg-destructive/10 border border-destructive/20 rounded-xl flex items-start gap-3">
              <AlertCircle className="w-4 h-4 text-destructive shrink-0 mt-0.5" />
              <p className="text-destructive text-sm font-medium">{getApiErrorMessage(leaveMutation.error)}</p>
            </div>
          )}
        </div>
      </HarmonyDialog>

      {/* ── EXTRA SHIFT MODAL ── */}
      <HarmonyDialog
        open={isExtraShiftModalOpen}
        onOpenChange={(open) => { if (!open) { setIsExtraShiftModalOpen(false); setSelectedExtraShiftDate(null); setExtraShiftReason(""); } }}
        title="Add Extra Shift"
        description={selectedExtraShiftDate ? format(parseISO(selectedExtraShiftDate), "EEEE, dd MMMM yyyy") : ""}
        size="md"
        onSubmit={handleExtraShiftSubmit}
        submitLabel="Add Shift"
        isSubmitting={false}
        submitDisabled={!extraShiftReason.trim()}
      >
        <div className="space-y-6">
          <div className="p-4 bg-primary/5 border border-primary/20 rounded-2xl flex items-start gap-3">
            <div className="w-6 h-6 bg-primary/20 rounded-lg flex items-center justify-center shrink-0 mt-0.5">
              <AlertCircle className="w-3.5 h-3.5 text-primary" />
            </div>
            <p className="text-foreground text-sm font-medium leading-relaxed">
              Adding an extra shift will credit <span className="font-bold">1 day</span> to your leave balance as a Comp-Off.
            </p>
          </div>

          <div className="space-y-3">
            <label className="ws-label">Reason for Extra Shift <span className="text-rose-500">*</span></label>
            <textarea
              value={extraShiftReason}
              onChange={(e) => setExtraShiftReason(e.target.value)}
              placeholder="e.g. Server maintenance, Urgent client delivery..."
              rows={4}
              className="w-full px-4 py-3 border border-border rounded-2xl text-sm text-foreground placeholder:text-muted-foreground font-medium focus:outline-none focus:ring-2 focus:ring-primary/30 focus:border-primary transition-all resize-none bg-muted/30"
            />
          </div>

          <div className="space-y-3">
            <label className="ws-label">Shift Type</label>
            <div className="grid grid-cols-3 gap-3">
              {[
                { label: "Morning", value: ShiftType.MorningShift, icon: SunMedium },
                { label: "Afternoon", value: ShiftType.AfternoonShift, icon: Clock },
                { label: "Night", value: ShiftType.NightShift, icon: EyeOff },
              ].map((s) => (
                <button
                  key={s.value}
                  onClick={() => setExtraShiftType(s.value)}
                  className={`flex flex-col items-center gap-1.5 py-2.5 rounded-xl border text-[11px] font-bold transition-all ${
                    extraShiftType === s.value
                      ? "bg-primary border-primary text-primary-foreground shadow-md"
                      : "bg-card border-border text-muted-foreground hover:bg-muted"
                  }`}
                >
                  <s.icon className={`w-3.5 h-3.5 ${extraShiftType === s.value ? "text-primary-foreground" : "text-muted-foreground"}`} />
                  {s.label}
                </button>
              ))}
            </div>
          </div>

        </div>
      </HarmonyDialog>
    </div>
  );
};

export default TeamSchedule;
