import { useQuery } from "@tanstack/react-query";
import { format } from "date-fns";
import { workScheduleService as accountService } from "@/api/workScheduleService";
import { publicHolidayService } from "@/api/publicHolidayService";
import { extraShiftService } from "@/api/extraShiftService";
import { normaliseHolidays } from "../utils";
import type { WorkScheduleResponse } from "../types";

export function useWorkScheduleData(year: number, month: number, isAdmin: boolean) {
  const scheduleQuery = useQuery<WorkScheduleResponse | WorkScheduleResponse[]>({
    queryKey: ["work-schedule", year, month, isAdmin],
    queryFn: () =>
      isAdmin
        ? accountService.getAllSchedules(year, month)
        : accountService.getTeamSchedules(year, month),
    retry: false,
    refetchInterval: isAdmin ? 5000 : false,
  });

  const extraShiftQuery = useQuery({
    queryKey: ["extra-shifts", year, month],
    queryFn: async () => {
      const start = format(new Date(year, month - 1, 1), "yyyy-MM-dd");
      const end = format(new Date(year, month, 0), "yyyy-MM-dd");
      return extraShiftService.getByRange(start, end);
    },
    staleTime: 1000 * 60 * 5, // 5 minutes
  });

  const holidayQuery = useQuery({
    queryKey: ["public-holidays"],
    queryFn: async () => normaliseHolidays(await publicHolidayService.getAll()),
    staleTime: 1000 * 60 * 60, // 1 hour
  });

  return {
    scheduleQuery,
    extraShiftQuery,
    holidayQuery,
  };
}
